class MyApp extends StatefulWidget {
  @override
  _MyAppState createState() => _MyAppState();
}

class _MyAppState extends State<MyApp> {
  String? _link;

  @override
  void initState() {
    super.initState();
    initDeepLinking();
  }

  Future<void> initDeepLinking() async {
    if (await UniLinks.isAvailable()) {
      final initialLink = await getInitialLink();

      if (initialLink != null) {
        handleLink(initialLink);
      }

      // Handle incoming links
      UniLinks.linkStream.listen((link) {
        if (link != null && link.isNotEmpty) {
          handleLink(link);
        }
      }).onError((error) {
        print('Deep Link error: $error');
      });
    } else {
      print('UniLinks are not available.');
    }
  }

  void handleLink(String link) {
    final uri = Uri.parse(link);

    if (uri.host == 'myapp') {
      switch (uri.path) {
        case '/profile':
          Navigator.push(
            context,
            MaterialPageRoute(builder: (context) => ProfilePage(uri.queryParameters['id'])),
          );
          break;
        case '/payment/confirm':
          Navigator.push(
            context,
            MaterialPageRoute(builder: (context) => PaymentConfirmPage()),
          );
          break;
        default:
          print('Unknown deep link path: ${uri.path}');
      }
    } else {
      print('Invalid deep link host: ${uri.host}');
    }
  }

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Deep Link Example',
      home: Scaffold(
        appBar: AppBar(title: Text('Deep Link Example')),
        body: Center(
          child: Text(_link ?? 'Waiting for a deep link...'),
        ),
      ),
    );
  }
}

